    uint32_t batchSize = shape.GetDim(0);
    uint32_t channels = shape.GetDim(1);
    uint32_t inDepth = shape.GetDim(2);
    uint32_t inHeight = shape.GetDim(3);
    uint32_t inWidth = shape.GetDim(4);

